type Prop = {
  isLink?: boolean;
  style?: React.CSSProperties;
};

export const IconR = ({ isLink = false, style = {} }: Prop) => (
  <Icon src="img/r.ico" isLink={isLink} style={style} />
);
export const IconZ = ({ isLink = false, style = {} }: Prop) => (
  <Icon src="img/z.ico" isLink={isLink} style={style} />
);
export const IconO = ({ isLink = false, style = {} }: Prop) => (
  <Icon src="img/o.ico" isLink={isLink} style={style} />
);

const Icon = ({
  isLink = false,
  style = {},
  src,
}: {
  isLink?: boolean;
  style?: React.CSSProperties;
  src: string;
}) => {
  style.width = isLink ? "1.4rem" : "1rem";
  return (
    <img
      loading="lazy"
      referrerPolicy="no-referrer"
      crossOrigin="anonymous"
      src={src}
      style={style}
      alt="z Property"
    />
  );
};
