import { IconR, IconZ, IconO } from "../Simple/Image";
import { Elem } from "../Simple/Elem";
import type { Item } from "../../types";
import { reduceBullet } from "../../utils/reduce";

export const Street = ({ item }: { item: Item }) => {
  const elems = [];
  elems.push(<ZooplaAdvertsInStreet key="1" item={item} />);
  elems.push(<OnTheMoveAdvertsInStreet key="2" item={item} />);
  elems.push(<ZooplaEstimatesInStreet key="3" item={item} />);
  elems.push(<SoldInStreet key="4" item={item} />, <StreetEPCs key="6" item={item} />);
  elems.push(<CrimeInStreet key="5" item={item} />);
  return (
    <p>
      <strong>In Street:</strong> {elems.reduce(reduceBullet)}
    </p>
  );
};

const SoldInStreet = ({ item }: { item: Item }) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const url = `https://www.rightmove.co.uk/house-prices/${postcode}.html`;
  return <Elem icon={<IconR />} url={url} text="Sold" />;
};

const ZooplaEstimatesInStreet = ({ item }: { item: Item }) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const postcodePlus: string = item.address_postcode.toUpperCase().replace(" ", "%20");
  const url = `https://www.zoopla.co.uk/house-prices/${postcode}/?q=${postcodePlus}&sortOrder=address&sortDirection=asc`;
  return <Elem icon={<IconZ />} url={url} text="Estimates / Sold" />;
};

/**
 * Adverts in street (no price/bedroom filter)
 */
const ZooplaAdvertsInStreet = ({ item }: { item: Item }) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const postcodePlus: string = item.address_postcode.replace(" ", "+");
  const url: string =
    item.channel === "rent"
      ? `https://www.zoopla.co.uk/to-rent/property/${postcode}/?radius=0&q=${postcodePlus}&search_source=to-rent&results_sort=newest_listings&include_rented=true`
      : `https://www.zoopla.co.uk/for-sale/property/${postcode}/?radius=0&q=${postcodePlus}&search_source=for-sale&results_sort=newest_listings&is_auction=false&is_retirement_home=false&is_shared_ownership=false&include_sold=true`;
  return <Elem icon={<IconZ />} url={url} text="Adverts" />;
};

const OnTheMoveAdvertsInStreet = ({ item }: { item: Item }) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const url: string =
    item.channel === "rent"
      ? `https://www.onthemarket.com/to-rent/property/${postcode}/?let-agreed=true&radius=0.25&shared=false&student=false&view=grid`
      : `https://www.onthemarket.com/for-sale/property/${postcode}/?auction=false&radius=0.25&retirement=false&shared-ownership=false&under-offer=true&view=grid`;
  return <Elem icon={<IconO />} url={url} text="Adverts" />;
};

const CrimeInStreet = ({ item }: { item: Item }) => {
  const postcode: string = item.address_postcode.toUpperCase().replace(" ", "%20");
  const url = `https://www.crime-statistics.co.uk/postcode/${postcode}`;
  const icon = <i className="fa-solid fa-handcuffs" style={{ color: "#808080" }} />;
  return <Elem icon={icon} url={url} text="Crimes" />;
};

/**
 * EPC
 */
const StreetEPCs = ({ item }: { item: Item }) => {
  const icon = <i className="fa-solid fa-leaf" style={{ color: "#659748" }} />;
  const postcodePlus: string = item.address_postcode.replace(" ", "+");
  const url = `https://find-energy-certificate.service.gov.uk/find-a-certificate/search-by-postcode?postcode=${postcodePlus}`;
  return <Elem icon={icon} url={url} text="EPCs" />;
};

export default Street;
